import React, { useState } from 'react';
import './EditMaterial.css';

const EditMaterial = ({ material, handleUpdate }) => {
  const [name, setName] = useState(material.name);
  const [description, setDescription] = useState(material.description);
  const [unitOfMeasure, setUnitOfMeasure] = useState(material.unit_of_measure);
  const [pricePerUnit, setPricePerUnit] = useState(material.price_per_unit);
  const [recentVendor, setRecentVendor] = useState(material.recent_vendor);

  const handleSubmit = (e) => {
    e.preventDefault();

    // Create an updatedMaterial object with the modified fields
    const updatedMaterial = {
      ...material,
      name,
      description,
      unit_of_measure: unitOfMeasure,
      price_per_unit: pricePerUnit,
      recent_vendor: recentVendor,
    };

    // Pass the updated material to the handleUpdate function
    handleUpdate(updatedMaterial);
  };

  return (
    <div className="edit-material-container">
      <h2 className="edit-material-heading">Edit Material</h2>
      <form className="edit-material-form" onSubmit={handleSubmit}>
        <div className="form-row">
          <div className="form-group">
            <label htmlFor="name">Name:</label>
            <input
              type="text"
              id="name"
              value={name}
              onChange={(e) => setName(e.target.value)}
            />
          </div>
          <div className="form-group">
            <label htmlFor="description">Description:</label>
            <textarea
              id="description"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
            />
          </div>
          <div className="form-group">
            <label htmlFor="unitOfMeasure">Unit of Measure:</label>
            <input
              type="text"
              id="unitOfMeasure"
              value={unitOfMeasure}
              onChange={(e) => setUnitOfMeasure(e.target.value)}
            />
          </div>
          <div className="form-group">
            <label htmlFor="pricePerUnit">Price per Unit:</label>
            <input
              type="number"
              id="pricePerUnit"
              value={pricePerUnit}
              onChange={(e) => setPricePerUnit(e.target.value)}
            />
          </div>
          <div className="form-group">
            <label htmlFor="recentVendor">Recent Vendor:</label>
            <input
              type="text"
              id="recentVendor"
              value={recentVendor}
              onChange={(e) => setRecentVendor(e.target.value)}
            />
          </div>
        </div>
        <button type="submit" className="edit-material-btn">Update</button>
      </form>
    </div>
  );
};

export default EditMaterial;
